/**
 * Webhook notification adapter.
 *
 * Implements NotificationAdapter for the 'webhook' channel.
 * Formats notification payloads as JSON and POSTs them to a configured URL.
 */

import type { NotificationAdapter, NotificationResult } from './notification.adapter.js';
import type { NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * The JSON body sent to the webhook endpoint.
 */
export interface WebhookBody {
  recipient: string;
  subject: string;
  body: string;
  type: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/**
 * Delivery function signature. Can be replaced for testing or to swap HTTP clients.
 */
export type WebhookDeliveryFn = (
  url: string,
  body: WebhookBody,
) => Promise<{ success: boolean; error?: string }>;

/**
 * Default delivery function that uses fetch to POST the payload.
 */
const fetchDelivery =
  (logger: Logger): WebhookDeliveryFn =>
  async (url, body) => {
    logger.info(`Delivering webhook to ${url}`);
    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    if (!response.ok) {
      return { success: false, error: `HTTP ${response.status}` };
    }
    return { success: true };
  };

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private url: string;
  private deliverFn: WebhookDeliveryFn;

  constructor(options: {
    url: string;
    deliverFn?: WebhookDeliveryFn;
  }) {
    this.url = options.url;
    this.deliverFn = options.deliverFn ?? fetchDelivery(this.logger);
  }

  /**
   * Resolve the target URL from the payload.
   * If metadata contains an explicit `webhookUrl`, use that;
   * otherwise fall back to the configured URL.
   */
  resolveUrl(payload: NotificationPayload): string {
    const override = payload.metadata?.['webhookUrl'];
    if (typeof override === 'string' && override.length > 0) {
      return override;
    }
    return this.url;
  }

  /**
   * Format the notification payload into a webhook JSON body.
   */
  formatBody(payload: NotificationPayload): WebhookBody {
    return {
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      type: payload.type,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Send a webhook notification.
   * Formats the payload as JSON and POSTs it to the target URL.
   * Never throws — returns a failed result on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const url = this.resolveUrl(payload);

      if (!url || url.trim().length === 0) {
        this.logger.warn('Cannot send webhook: no URL configured');
        return { success: false, channel: 'webhook', error: 'No webhook URL configured' };
      }

      const body = this.formatBody(payload);

      this.logger.info(`Sending ${payload.type} webhook to ${url}`);
      const result = await this.deliverFn(url, body);

      if (!result.success) {
        this.logger.error(`Failed to deliver webhook to ${url}: ${result.error}`);
        return { success: false, channel: 'webhook', error: result.error };
      }

      this.logger.info(`Webhook delivered to ${url}`);
      return { success: true, channel: 'webhook' };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(`Webhook send error: ${message}`);
      return { success: false, channel: 'webhook', error: message };
    }
  }
}

import { describe, it, expect, vi } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';
import type { WebhookDeliveryFn, WebhookBody } from '../../src/adapters/webhook.adapter.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'user-123',
    subject: 'Test Subject',
    body: 'Test body content',
    type: 'order-confirmation',
    channel: 'webhook',
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  describe('channel', () => {
    it('should have channel set to webhook', () => {
      const adapter = new WebhookAdapter({ url: 'https://example.com/hook' });
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('resolveUrl', () => {
    it('should use configured URL by default', () => {
      const adapter = new WebhookAdapter({ url: 'https://example.com/hook' });
      const payload = makePayload();
      expect(adapter.resolveUrl(payload)).toBe('https://example.com/hook');
    });

    it('should use webhookUrl from metadata when present', () => {
      const adapter = new WebhookAdapter({ url: 'https://example.com/hook' });
      const payload = makePayload({
        metadata: { webhookUrl: 'https://override.com/hook' },
      });
      expect(adapter.resolveUrl(payload)).toBe('https://override.com/hook');
    });

    it('should fall back to configured URL when metadata webhookUrl is empty', () => {
      const adapter = new WebhookAdapter({ url: 'https://example.com/hook' });
      const payload = makePayload({
        metadata: { webhookUrl: '' },
      });
      expect(adapter.resolveUrl(payload)).toBe('https://example.com/hook');
    });
  });

  describe('formatBody', () => {
    it('should format payload as webhook JSON body', () => {
      const adapter = new WebhookAdapter({ url: 'https://example.com/hook' });
      const payload = makePayload();
      const body = adapter.formatBody(payload);

      expect(body.recipient).toBe('user-123');
      expect(body.subject).toBe('Test Subject');
      expect(body.body).toBe('Test body content');
      expect(body.type).toBe('order-confirmation');
      expect(body.timestamp).toBeDefined();
    });

    it('should include metadata in the body', () => {
      const adapter = new WebhookAdapter({ url: 'https://example.com/hook' });
      const payload = makePayload({ metadata: { orderId: 'ord-001' } });
      const body = adapter.formatBody(payload);

      expect(body.metadata).toEqual({ orderId: 'ord-001' });
    });
  });

  describe('send', () => {
    it('should deliver webhook successfully', async () => {
      const deliverFn: WebhookDeliveryFn = vi.fn(async () => ({ success: true }));
      const adapter = new WebhookAdapter({ url: 'https://example.com/hook', deliverFn });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');
      expect(result.error).toBeUndefined();
    });

    it('should call delivery function with correct URL and body', async () => {
      const deliverFn: WebhookDeliveryFn = vi.fn(async () => ({ success: true }));
      const adapter = new WebhookAdapter({ url: 'https://example.com/hook', deliverFn });

      await adapter.send(makePayload());

      expect(deliverFn).toHaveBeenCalledOnce();
      const [url, body] = vi.mocked(deliverFn).mock.calls[0]!;
      expect(url).toBe('https://example.com/hook');
      expect(body.recipient).toBe('user-123');
      expect(body.subject).toBe('Test Subject');
      expect(body.type).toBe('order-confirmation');
    });

    it('should return failure when delivery fails', async () => {
      const deliverFn: WebhookDeliveryFn = vi.fn(async () => ({
        success: false,
        error: 'HTTP 500',
      }));
      const adapter = new WebhookAdapter({ url: 'https://example.com/hook', deliverFn });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.channel).toBe('webhook');
      expect(result.error).toBe('HTTP 500');
    });

    it('should return failure when delivery throws', async () => {
      const deliverFn: WebhookDeliveryFn = vi.fn(async () => {
        throw new Error('Network error');
      });
      const adapter = new WebhookAdapter({ url: 'https://example.com/hook', deliverFn });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.channel).toBe('webhook');
      expect(result.error).toBe('Network error');
    });

    it('should return failure when URL is empty', async () => {
      const adapter = new WebhookAdapter({ url: '' });
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('No webhook URL');
    });

    it('should use webhookUrl from metadata to override configured URL', async () => {
      const deliverFn: WebhookDeliveryFn = vi.fn(async () => ({ success: true }));
      const adapter = new WebhookAdapter({ url: 'https://example.com/hook', deliverFn });

      await adapter.send(
        makePayload({ metadata: { webhookUrl: 'https://override.com/hook' } }),
      );

      const [url] = vi.mocked(deliverFn).mock.calls[0]!;
      expect(url).toBe('https://override.com/hook');
    });
  });
});

